  const notificationElem = useContext(NotificationContext);
  const [element, setElement] = useState<HTMLHuelNotificationElement | null>(null);

  useEffect(() => {
    const notificationElement = document.querySelector('huel-notification');
    if (notificationElement) {
      setElement(notificationElement as HTMLHuelNotificationElement);
    }
  }, []);

  const notify = async (props: NotificationProps) => {
    if (!element) return;

    const { heading, subheading, type } = props;
    await element.open({
      heading,
      subheading,
      type,
    });
  };

  return { notify };
