public abstract class BaseRepository<T> where T : class
{
    protected readonly DbContext _context;

    public BaseRepository(DbContext context)
    {
        _context = context;
    }

    public virtual IQueryable<T> GetAll()
    {
        return _context.Set<T>().AsQueryable();
    }

    public virtual IQueryable<T> GetByDynamicField(string fieldName, object value)
    {
        var propertyInfo = typeof(T).GetProperty(fieldName);
        if (propertyInfo == null)
        {
            throw new ArgumentException($"Property '{fieldName}' does not exist.");
        }

        var parameter = Expression.Parameter(typeof(T), "t");
        var memberExpression = Expression.MakeMemberAccess(parameter, propertyInfo);
        var constantExpression = Expression.Constant(value);
        var body = Expression.Equal(memberExpression, constantExpression);
